import { Alert } from 'react-native';

function ProfilScreen({ navigation, route }) {
  const { pseudo } = route.params;

  useLayoutEffect(() => {
    navigation.setOptions({
      title: pseudo,
      headerRight: () => (
        <Button
          title="Déconnexion"
          onPress={() => {
            Alert.alert('Déconnexion', 'Vous êtes déconnecté');
            navigation.goBack();
          }}
        />
      ),
    });
  }, [navigation, pseudo]);

